Function: package main

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"os/signal"
	"strings"
	"syscall"
	"time"

	"github.com/gorilla/websocket"
)

const data_path = "/app/data"

type statusHandler struct {
	data string
}

func makeStatusHandler() *statusHandler {
	var h statusHandler
	raw, err := os.ReadFile(data_path)
	if err != nil {
		log.Printf("failed to read the haystack, %s\n", err)
		h.data = "{}"
		return &h
	}
	h.data = string(raw)
	return &h
}

func (sh *statusHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	log.Printf("handling request from %s", r.RemoteAddr)
	var data map[string]interface{}
	err := json.Unmarshal([]byte(sh.data), &data)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		w.Write([]byte(fmt.Sprintf("{"error": "%s"}", err)))
		return
	}

	keys := []string{}
	for k := range data {
		keys = append(keys, k)
	}

	if strings.Contains(r.URL.Path, "full") {
		bytes, err := json.Marshal(data)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			w.Write([]byte(fmt.Sprintf("{"error": "%s"}", err)))
			return
		}
		w.Write(bytes)
		return
	}
	bytes, err := json.Marshal(keys)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		w.Write([]byte(fmt.Sprintf("{"error": "%s"}", err)))
		return
	}
	w.Write(bytes)
}

func makeLogHandler() http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		log.Printf("handling log request from %s", r.RemoteAddr)
		upgrader := websocket.Upgrader{}
		conn, err := upgrader.Upgrade(w, r, nil)
		if err != nil {
			log.Printf("failed to upgrade, %s\n", err)
			return
		}

		defer conn.Close()

		file, err := os.Open("/var/log/system.log")
		if err != nil {
			conn.WriteMessage(websocket.TextMessage, []byte("failed to open log"))
			return
		}
		defer file.Close()

		buf := make([]byte, 1024)
		sent := 0
		for sent < 5 {
			n, err := file.Read(buf)
			if err != nil && err != io.EOF {
				conn.WriteMessage(websocket.TextMessage, []byte("failed to read log"))
				return
			}
			if n == 0 {
				break
			}
			err = conn.WriteMessage(websocket.TextMessage, buf[:n])
			sent++
			if err != nil {
				log.Printf("failed to write message, %s\n", err)
				return
			}
		}
		conn.WriteMessage(websocket.TextMessage, []byte("sent maximum lines"))
		conn.Close()
	})
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/status", makeStatusHandler())
	mux.Handle("/log", GzipMiddleware(makeLogHandler()))

	srv := &http.Server{
		Addr:    ":8080",
		Handler: mux,
	}

	done := make(chan os.Signal, 1)
	signal.Notify(done, os.Interrupt, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		log.Printf("server starting on :8080\n")
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("listen: %s\n", err)
		}
	}()

	<-done
	log.Printf("server stopping\n")

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := srv.Shutdown(ctx); err != nil {
		log.Fatalf("shutdown failed:%+v\n", err)
	}
	log.Printf("server exited\n")
}
